mapper.select:
/* adm-role-centerbyrole-sql-oracle.xml - selectTAdminMstRoxctgt */
SELECT '0' AS CHK
       ,CTKEY
       ,ROKEY
  FROM TADMIN_MST_ROXCTGT
 WHERE ROKEY = #{rokey}

mapper.insert:
/* adm-role-centerbyrole-sql-oracle.xml - insertTAdminMstRoxctgt */
INSERT INTO TADMIN_MST_ROXCTGT (
	 ROKEY
	 ,CTKEY
	 ,INSERTURKEY
	 ,INSERTDATE
	 ,UPDATEURKEY
	 ,UPDATEDATE
) VALUES ( 
	 #{rokey}
	 ,#{ctkey}
	 ,#{surkey}
	 ,#{sysdate}
	 ,#{surkey}
	 ,#{sysdate}
)

mapper.delete:
/* adm-role-centerbyrole-sql-oracle.xml - deleteTAdminMstRoxctgt */
DELETE 
  FROM TADMIN_MST_ROXCTGT
 WHERE CTKEY = #{ctkey}

 AND ROKEY = #{rokey}
